/* a+ core 2 :: content/questions1.js — Domain 1 Operating Systems (220-1202). */
window.APLUS2 = window.APLUS2 || {};
APLUS2.questions = APLUS2.questions || [];
APLUS2.questions.push(
{ id:"D1-001", domain:1, obj:"1.2", diff:"easy", q:"Which command displays the current TCP/IP configuration including the IPv4 address, subnet mask, and default gateway on a Windows machine?", options:["ping","ipconfig","tracert","netstat"], answer:1, explain:"<strong>ipconfig</strong> is correct because it reports the local adapter's IP address, subnet mask, and default gateway, and with /all shows DNS and DHCP details.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ping</b>: tests reachability to a host, it does not show your own configuration.</span><span class='qd'><b>tracert</b>: maps the hops to a destination, not the local settings.</span><span class='qd'><b>netstat</b>: lists active connections and listening ports, not adapter configuration.</span>" },
{ id:"D1-002", domain:1, obj:"1.2", diff:"easy", q:"A technician wants to test whether a remote server at 8.8.8.8 is reachable across the network. Which command is the most direct choice?", options:["ping 8.8.8.8","format 8.8.8.8","chkdsk 8.8.8.8","sfc 8.8.8.8"], answer:0, explain:"<strong>ping 8.8.8.8</strong> is correct because ping sends ICMP echo requests and reports whether replies are received and the round-trip time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>format 8.8.8.8</b>: format prepares a disk volume and takes a drive letter, not an IP.</span><span class='qd'><b>chkdsk 8.8.8.8</b>: chkdsk checks a disk for errors, it does not test network reachability.</span><span class='qd'><b>sfc 8.8.8.8</b>: sfc scans system files; it has no networking function.</span>" },
{ id:"D1-003", domain:1, obj:"1.2", diff:"medium", q:"A user reports that web pages will not load by name but works when the IP is typed directly. Which command best helps the technician confirm name resolution is the problem?", options:["chkdsk","nslookup","robocopy","diskpart"], answer:1, explain:"<strong>nslookup</strong> is correct because it queries DNS directly and shows whether a hostname resolves to an IP address, isolating name resolution issues.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chkdsk</b>: checks file system integrity, unrelated to DNS.</span><span class='qd'><b>robocopy</b>: copies files and directories, not a diagnostic tool.</span><span class='qd'><b>diskpart</b>: manages disk partitions, not name resolution.</span>" },
{ id:"D1-004", domain:1, obj:"1.2", diff:"medium", q:"A technician needs to view the path packets take to a remote host and identify which hop introduces high latency. Which command should be used?", options:["hostname","tracert","tasklist","winver"], answer:1, explain:"<strong>tracert</strong> is correct because it lists each router hop to the destination along with per-hop round-trip times, exposing where delay occurs.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>hostname</b>: only prints the local computer name.</span><span class='qd'><b>tasklist</b>: lists running processes, not network paths.</span><span class='qd'><b>winver</b>: shows the Windows version, no network function.</span>" },
{ id:"D1-005", domain:1, obj:"1.2", diff:"hard", q:"A technician suspects packet loss occurring at a specific router along a multi-hop path and wants a tool that combines a hop trace with sustained statistics about loss at each hop. Which command is best?", options:["ping","tracert","pathping","netstat"], answer:2, explain:"<strong>pathping</strong> is correct because it traces the route and then sends packets over time to each hop, reporting per-hop latency and packet loss percentages.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ping</b>: tests only one endpoint, not per-hop loss.</span><span class='qd'><b>tracert</b>: shows hops and latency but does not gather sustained loss statistics per hop.</span><span class='qd'><b>netstat</b>: shows local connections, not path loss.</span>" },
{ id:"D1-006", domain:1, obj:"1.2", diff:"medium", q:"A technician wants to release and renew a workstation's DHCP-assigned address. Which two ipconfig switches accomplish this?", options:["/flushdns then /registerdns","/release then /renew","/all then /displaydns","/setclassid then /showclassid"], answer:1, explain:"<strong>/release then /renew</strong> is correct because /release drops the current DHCP lease and /renew requests a new one from the DHCP server.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>/flushdns then /registerdns</b>: these manage the DNS resolver cache and registration, not the DHCP lease.</span><span class='qd'><b>/all then /displaydns</b>: /all shows full config and /displaydns shows the cache; neither changes the lease.</span><span class='qd'><b>/setclassid then /showclassid</b>: these manage DHCP class IDs, not lease renewal.</span>" },
{ id:"D1-007", domain:1, obj:"1.2", diff:"easy", q:"Which command clears the local DNS resolver cache on Windows?", options:["ipconfig /flushdns","ipconfig /release","ipconfig /all","ipconfig /renew"], answer:0, explain:"<strong>ipconfig /flushdns</strong> is correct because it purges cached DNS records, forcing fresh lookups which helps after a DNS change.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ipconfig /release</b>: drops the DHCP lease.</span><span class='qd'><b>ipconfig /all</b>: only displays configuration.</span><span class='qd'><b>ipconfig /renew</b>: requests a new DHCP lease.</span>" },
{ id:"D1-008", domain:1, obj:"1.2", diff:"medium", q:"A user complains a drive is reporting errors. The technician wants to scan and automatically fix file system errors and recover readable information from bad sectors. Which command and switches are appropriate?", options:["sfc /scannow","chkdsk /f /r","diskpart clean","format /q"], answer:1, explain:"<strong>chkdsk /f /r</strong> is correct because /f fixes file system errors and /r locates bad sectors and recovers readable data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>sfc /scannow</b>: repairs protected system files, not disk sectors.</span><span class='qd'><b>diskpart clean</b>: erases the partition table, destroying data.</span><span class='qd'><b>format /q</b>: performs a quick format, erasing the volume.</span>" },
{ id:"D1-009", domain:1, obj:"1.2", diff:"medium", q:"A Windows machine boots with corrupted protected system files. Which command scans and repairs Windows system file integrity?", options:["chkdsk","sfc /scannow","gpupdate /force","netstat -an"], answer:1, explain:"<strong>sfc /scannow</strong> is correct because System File Checker verifies the integrity of protected operating system files and replaces corrupted ones.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chkdsk</b>: checks disk and file system structures, not OS file integrity.</span><span class='qd'><b>gpupdate /force</b>: refreshes Group Policy settings.</span><span class='qd'><b>netstat -an</b>: shows network connections numerically.</span>" },
{ id:"D1-010", domain:1, obj:"1.2", diff:"hard", q:"After sfc reports it could not repair a file, a technician decides to repair the underlying Windows component store image online. Which command is appropriate?", options:["dism /online /cleanup-image /restorehealth","chkdsk /f","sfc /verifyonly","diskpart list disk"], answer:0, explain:"<strong>dism /online /cleanup-image /restorehealth</strong> is correct because DISM repairs the Windows component store that sfc relies on, often run before re-running sfc.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chkdsk /f</b>: fixes disk errors, not the component store.</span><span class='qd'><b>sfc /verifyonly</b>: only checks without repairing.</span><span class='qd'><b>diskpart list disk</b>: lists disks, no repair function.</span>" },
{ id:"D1-011", domain:1, obj:"1.2", diff:"medium", q:"In a domain environment, a technician changed a Group Policy and wants the client to apply it immediately rather than waiting for the refresh interval. Which command is correct?", options:["gpresult /r","gpupdate /force","net use","tasklist /svc"], answer:1, explain:"<strong>gpupdate /force</strong> is correct because it forces an immediate reapplication of all Group Policy settings on the client.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>gpresult /r</b>: reports applied policies but does not refresh them.</span><span class='qd'><b>net use</b>: manages network drive mappings.</span><span class='qd'><b>tasklist /svc</b>: lists processes and their services.</span>" },
{ id:"D1-012", domain:1, obj:"1.2", diff:"medium", q:"A technician needs to verify which Group Policy objects are currently applied to a user and computer. Which command produces this summary?", options:["gpupdate /force","gpresult /r","net config","ipconfig /all"], answer:1, explain:"<strong>gpresult /r</strong> is correct because it displays the Resultant Set of Policy, listing which GPOs apply to the user and computer.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>gpupdate /force</b>: applies policy but does not report results.</span><span class='qd'><b>net config</b>: shows workstation/server service settings.</span><span class='qd'><b>ipconfig /all</b>: shows IP configuration only.</span>" },
{ id:"D1-013", domain:1, obj:"1.2", diff:"hard", q:"A technician must mirror an entire directory tree to a backup server, copying only changed files on subsequent runs and including subdirectories and empty folders. Which command and switch best fits?", options:["xcopy /s","robocopy /mir","copy /y","format /fs:NTFS"], answer:1, explain:"<strong>robocopy /mir</strong> is correct because /mir mirrors a directory tree including subdirectories and empty folders, copying only differences and removing files no longer in the source.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>xcopy /s</b>: copies subdirectories but cannot mirror or efficiently sync, and is deprecated in favor of robocopy.</span><span class='qd'><b>copy /y</b>: copies single files without subdirectory support.</span><span class='qd'><b>format /fs:NTFS</b>: formats a volume, it does not copy files.</span>" },
{ id:"D1-014", domain:1, obj:"1.2", diff:"easy", q:"Which legacy command copies files and directory trees and supports the /s switch to include subdirectories?", options:["robocopy","xcopy","diskpart","winver"], answer:1, explain:"<strong>xcopy</strong> is correct because xcopy is the legacy directory copy tool that uses /s to include nonempty subdirectories.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>robocopy</b>: is also a copy tool but its mirroring switch is /mir, and the question references the legacy /s tool.</span><span class='qd'><b>diskpart</b>: manages partitions.</span><span class='qd'><b>winver</b>: shows the OS version.</span>" },
{ id:"D1-015", domain:1, obj:"1.2", diff:"easy", q:"Which command displays the version of Windows currently installed in a simple dialog box?", options:["winver","hostname","ver /all","sysinfo"], answer:0, explain:"<strong>winver</strong> is correct because winver opens an About Windows dialog showing the edition, version, and build number.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>hostname</b>: prints the computer name only.</span><span class='qd'><b>ver /all</b>: ver shows a version string but /all is not a valid switch.</span><span class='qd'><b>sysinfo</b>: not a valid Windows command; systeminfo is the real tool.</span>" },
{ id:"D1-016", domain:1, obj:"1.2", diff:"medium", q:"A technician wants to terminate a process by its PID from the command line. Which command does this?", options:["tasklist /pid 1234","taskkill /pid 1234 /f","shutdown /pid 1234","net stop 1234"], answer:1, explain:"<strong>taskkill /pid 1234 /f</strong> is correct because taskkill ends a process by PID and /f forces termination of unresponsive processes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>tasklist /pid 1234</b>: only lists the process, it does not end it.</span><span class='qd'><b>shutdown /pid 1234</b>: shutdown controls power state, not processes.</span><span class='qd'><b>net stop 1234</b>: stops a named service, not a PID.</span>" },
{ id:"D1-017", domain:1, obj:"1.2", diff:"easy", q:"Which command lists all currently running processes from the Windows command line?", options:["tasklist","taskkill","tasksched","procmon"], answer:0, explain:"<strong>tasklist</strong> is correct because it outputs a table of running processes with image names, PIDs, and memory usage.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>taskkill</b>: ends processes, it does not list them.</span><span class='qd'><b>tasksched</b>: not a valid command.</span><span class='qd'><b>procmon</b>: Process Monitor is a Sysinternals GUI tool, not a built-in command.</span>" },
{ id:"D1-018", domain:1, obj:"1.2", diff:"medium", q:"A technician needs to map a network share to drive letter Z: from the command line. Which command is correct?", options:["net user Z: \\\\server\\share","net use Z: \\\\server\\share","net share Z: \\\\server\\share","net config Z: \\\\server\\share"], answer:1, explain:"<strong>net use Z: \\\\server\\share</strong> is correct because net use maps a drive letter to a network share.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>net user Z: \\\\server\\share</b>: net user manages user accounts.</span><span class='qd'><b>net share Z: \\\\server\\share</b>: net share creates a share on the local machine, not a mapping.</span><span class='qd'><b>net config Z: \\\\server\\share</b>: net config shows service settings.</span>" },
{ id:"D1-019", domain:1, obj:"1.2", diff:"medium", q:"A technician must reset a local user account password from an elevated command prompt. Which command does this?", options:["net user jsmith NewPass1 *","net use jsmith NewPass1","net localgroup jsmith NewPass1","gpresult jsmith"], answer:0, explain:"<strong>net user jsmith NewPass1</strong> is correct because net user with a username and password sets that account's password (an asterisk prompts interactively).<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>net use jsmith NewPass1</b>: net use maps network drives.</span><span class='qd'><b>net localgroup jsmith NewPass1</b>: net localgroup manages group membership.</span><span class='qd'><b>gpresult jsmith</b>: reports policy, not password changes.</span>" },
{ id:"D1-020", domain:1, obj:"1.2", diff:"easy", q:"Which command schedules or initiates a system shutdown with a timeout, for example restarting in 60 seconds?", options:["shutdown /r /t 60","reboot /t 60","logoff /t 60","restart -t 60"], answer:0, explain:"<strong>shutdown /r /t 60</strong> is correct because shutdown with /r restarts and /t sets the timeout in seconds.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>reboot /t 60</b>: reboot is not a native Windows command.</span><span class='qd'><b>logoff /t 60</b>: logoff signs out a session and has no /t timeout.</span><span class='qd'><b>restart -t 60</b>: restart is not a valid Windows command.</span>" },
{ id:"D1-021", domain:1, obj:"1.2", diff:"easy", q:"Which command displays active network connections and listening ports on a Windows host?", options:["nslookup","netstat","ping","tracert"], answer:1, explain:"<strong>netstat</strong> is correct because it lists active TCP/UDP connections, listening ports, and associated states.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>nslookup</b>: queries DNS records.</span><span class='qd'><b>ping</b>: tests reachability.</span><span class='qd'><b>tracert</b>: traces the path to a host.</span>" },
{ id:"D1-022", domain:1, obj:"1.2", diff:"easy", q:"Which command prints only the local computer's name?", options:["winver","hostname","whoami","ver"], answer:1, explain:"<strong>hostname</strong> is correct because it outputs the local machine's host name.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>winver</b>: shows the Windows version dialog.</span><span class='qd'><b>whoami</b>: shows the current user account, not the host name.</span><span class='qd'><b>ver</b>: shows the OS version string.</span>" },
{ id:"D1-023", domain:1, obj:"1.2", diff:"medium", q:"A technician is working in a script and needs to clear all text from the command prompt window. Which command does this?", options:["cls","clear","del","wipe"], answer:0, explain:"<strong>cls</strong> is correct because cls clears the Windows command prompt screen.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>clear</b>: clear is the Linux/macOS equivalent, not native Windows cmd.</span><span class='qd'><b>del</b>: deletes files.</span><span class='qd'><b>wipe</b>: not a built-in command.</span>" },
{ id:"D1-024", domain:1, obj:"1.2", diff:"easy", q:"Which command creates a new directory named Reports in the current location?", options:["cd Reports","md Reports","dir Reports","rd Reports"], answer:1, explain:"<strong>md Reports</strong> is correct because md (or mkdir) creates a new directory.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cd Reports</b>: changes into a directory, it does not create one.</span><span class='qd'><b>dir Reports</b>: lists directory contents.</span><span class='qd'><b>rd Reports</b>: removes a directory.</span>" },
{ id:"D1-025", domain:1, obj:"1.2", diff:"easy", q:"Which command lists the files and subdirectories in the current directory on Windows?", options:["ls","dir","cat","pwd"], answer:1, explain:"<strong>dir</strong> is correct because dir lists files and folders in the current directory on Windows.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ls</b>: is the Linux/macOS listing command.</span><span class='qd'><b>cat</b>: displays file contents on Unix-like systems.</span><span class='qd'><b>pwd</b>: prints the working directory on Unix-like systems.</span>" },
{ id:"D1-026", domain:1, obj:"1.2", diff:"hard", q:"A technician needs to script the creation of a new primary partition on disk 1 from the command line without a GUI. Which utility provides interactive commands like select disk and create partition primary?", options:["chkdsk","diskpart","robocopy","format"], answer:1, explain:"<strong>diskpart</strong> is correct because diskpart is the command-line disk partitioning utility supporting select disk, create partition, and assign.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chkdsk</b>: checks disk errors, it does not partition.</span><span class='qd'><b>robocopy</b>: copies files.</span><span class='qd'><b>format</b>: formats an existing volume, it does not create partitions.</span>" },
{ id:"D1-027", domain:1, obj:"1.2", diff:"medium", q:"A technician wants to format a USB drive as exFAT from the command line. Which command is correct?", options:["diskpart /fs:exFAT","format E: /fs:exFAT","chkdsk E: /fs:exFAT","convert E: /fs:exFAT"], answer:1, explain:"<strong>format E: /fs:exFAT</strong> is correct because format with /fs specifies the file system to apply to the volume.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>diskpart /fs:exFAT</b>: diskpart uses its own format command, not this syntax.</span><span class='qd'><b>chkdsk E: /fs:exFAT</b>: chkdsk checks disks and has no /fs format option.</span><span class='qd'><b>convert E: /fs:exFAT</b>: convert only changes FAT32 to NTFS.</span>" },
{ id:"D1-028", domain:1, obj:"1.2", diff:"hard", q:"A user reports intermittent disconnects. A technician wants to view per-protocol statistics and the route table to confirm there is no rogue default route. Which command provides the local routing table and connection info?", options:["netstat -r","ping -t","nslookup -debug","ipconfig /displaydns"], answer:0, explain:"<strong>netstat -r</strong> is correct because netstat -r displays the IP routing table, equivalent to route print, useful for spotting incorrect routes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ping -t</b>: pings continuously, no routing table.</span><span class='qd'><b>nslookup -debug</b>: returns DNS debug data, not routes.</span><span class='qd'><b>ipconfig /displaydns</b>: shows the DNS cache, not the route table.</span>" },
{ id:"D1-029", domain:1, obj:"1.2", diff:"medium", q:"A technician wants to navigate from C:\\Users\\Tech to C:\\Logs in the command prompt. Which command does this?", options:["dir C:\\Logs","cd C:\\Logs","md C:\\Logs","copy C:\\Logs"], answer:1, explain:"<strong>cd C:\\Logs</strong> is correct because cd (change directory) moves the prompt to the specified path.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dir C:\\Logs</b>: lists contents without changing location.</span><span class='qd'><b>md C:\\Logs</b>: creates a directory.</span><span class='qd'><b>copy C:\\Logs</b>: copies files.</span>" },
{ id:"D1-030", domain:1, obj:"1.2", diff:"hard", q:"A technician needs to query a specific DNS record type, such as the MX records for a domain, to troubleshoot mail delivery. Which interactive approach works?", options:["Use nslookup, set type=MX, then enter the domain","Use ping with the -mx switch","Use netstat -mx domain.com","Use tracert with /mx domain.com"], answer:0, explain:"<strong>Use nslookup, set type=MX, then enter the domain</strong> is correct because nslookup supports setting the query type to MX to return mail exchange records.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use ping with the -mx switch</b>: ping has no MX capability.</span><span class='qd'><b>Use netstat -mx domain.com</b>: netstat has no MX option and does not query DNS.</span><span class='qd'><b>Use tracert with /mx domain.com</b>: tracert traces hops, not DNS records.</span>" },
{ id:"D1-031", domain:1, obj:"1.3", diff:"easy", q:"Which built-in Windows tool shows real-time CPU, memory, disk, and network usage and lets you end an unresponsive application?", options:["Task Manager","Disk Management","Registry Editor","Event Viewer"], answer:0, explain:"<strong>Task Manager</strong> is correct because it displays live performance metrics and process control, including ending tasks.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disk Management</b>: manages partitions and volumes.</span><span class='qd'><b>Registry Editor</b>: edits the registry database.</span><span class='qd'><b>Event Viewer</b>: reviews logged system events.</span>" },
{ id:"D1-032", domain:1, obj:"1.3", diff:"medium", q:"A technician needs to disable a startup program and adjust boot options like safe boot. Which command opens the System Configuration utility?", options:["regedit","msconfig","services.msc","devmgmt.msc"], answer:1, explain:"<strong>msconfig</strong> is correct because System Configuration manages boot options, services, and startup settings.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>regedit</b>: opens the Registry Editor.</span><span class='qd'><b>services.msc</b>: manages individual services but not boot options.</span><span class='qd'><b>devmgmt.msc</b>: opens Device Manager.</span>" },
{ id:"D1-033", domain:1, obj:"1.3", diff:"easy", q:"Which command opens the Windows Registry Editor?", options:["regedit","regsvr32","reg add","msinfo32"], answer:0, explain:"<strong>regedit</strong> is correct because regedit launches the graphical Registry Editor for viewing and editing registry hives.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>regsvr32</b>: registers DLL files, not the editor.</span><span class='qd'><b>reg add</b>: adds keys via command line, not the GUI editor.</span><span class='qd'><b>msinfo32</b>: opens System Information.</span>" },
{ id:"D1-034", domain:1, obj:"1.3", diff:"easy", q:"Which console opens the Services management snap-in where services can be started, stopped, and set to automatic?", options:["taskmgr","services.msc","eventvwr","resmon"], answer:1, explain:"<strong>services.msc</strong> is correct because it opens the Services snap-in for managing service startup type and state.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>taskmgr</b>: opens Task Manager.</span><span class='qd'><b>eventvwr</b>: opens Event Viewer.</span><span class='qd'><b>resmon</b>: opens Resource Monitor.</span>" },
{ id:"D1-035", domain:1, obj:"1.3", diff:"medium", q:"An administrator wants a customizable console that can host multiple snap-ins such as Device Manager and Disk Management in one window. Which tool provides this?", options:["Microsoft Management Console (mmc)","Control Panel","Settings app","Command Prompt"], answer:0, explain:"<strong>Microsoft Management Console (mmc)</strong> is correct because MMC hosts and combines management snap-ins into a single customizable console.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Control Panel</b>: contains applets but is not a snap-in host.</span><span class='qd'><b>Settings app</b>: is the modern configuration UI, not a snap-in console.</span><span class='qd'><b>Command Prompt</b>: runs commands, it does not host snap-ins.</span>" },
{ id:"D1-036", domain:1, obj:"1.3", diff:"easy", q:"Which command opens Device Manager where hardware devices and drivers are managed?", options:["diskmgmt.msc","devmgmt.msc","compmgmt.msc","perfmon"], answer:1, explain:"<strong>devmgmt.msc</strong> is correct because it opens Device Manager for viewing devices, updating drivers, and resolving conflicts.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>diskmgmt.msc</b>: opens Disk Management.</span><span class='qd'><b>compmgmt.msc</b>: opens Computer Management.</span><span class='qd'><b>perfmon</b>: opens Performance Monitor.</span>" },
{ id:"D1-037", domain:1, obj:"1.3", diff:"medium", q:"A technician needs to create and format a new volume on a recently installed drive using a graphical interface. Which tool is best?", options:["Disk Management","Task Manager","Registry Editor","Event Viewer"], answer:0, explain:"<strong>Disk Management</strong> is correct because it provides a GUI for initializing disks, creating partitions, formatting volumes, and assigning drive letters.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Task Manager</b>: monitors performance and processes.</span><span class='qd'><b>Registry Editor</b>: edits registry keys.</span><span class='qd'><b>Event Viewer</b>: reviews logs.</span>" },
{ id:"D1-038", domain:1, obj:"1.3", diff:"medium", q:"A technician needs to review logged system errors and warnings to investigate a recurring crash. Which tool should be used?", options:["Event Viewer","Resource Monitor","Disk Management","Task Scheduler"], answer:0, explain:"<strong>Event Viewer</strong> is correct because it stores System, Application, and Security logs containing errors, warnings, and informational events.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Resource Monitor</b>: shows real-time resource usage.</span><span class='qd'><b>Disk Management</b>: manages volumes.</span><span class='qd'><b>Task Scheduler</b>: schedules automated tasks.</span>" },
{ id:"D1-039", domain:1, obj:"1.3", diff:"medium", q:"A technician wants to automate a maintenance script to run every night at 2 AM. Which Windows tool is designed for this?", options:["Task Manager","Task Scheduler","Services","Performance Monitor"], answer:1, explain:"<strong>Task Scheduler</strong> is correct because it creates triggers and actions to run programs or scripts automatically on a schedule.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Task Manager</b>: monitors and ends running tasks.</span><span class='qd'><b>Services</b>: manages background services, not scheduled scripts.</span><span class='qd'><b>Performance Monitor</b>: tracks performance counters.</span>" },
{ id:"D1-040", domain:1, obj:"1.3", diff:"hard", q:"A technician wants to collect and log specific performance counters over a period to analyze a slow server and create a data collector set. Which tool provides this?", options:["Resource Monitor","Performance Monitor","Task Manager","Event Viewer"], answer:1, explain:"<strong>Performance Monitor</strong> is correct because perfmon allows creating data collector sets and logging specific counters over time for analysis.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Resource Monitor</b>: shows live usage but does not build data collector sets.</span><span class='qd'><b>Task Manager</b>: shows snapshot performance, not logged counters.</span><span class='qd'><b>Event Viewer</b>: logs events, not performance counters.</span>" },
{ id:"D1-041", domain:1, obj:"1.3", diff:"medium", q:"A technician wants a real-time, detailed breakdown of which processes are using the disk, network, and memory at the moment, more granular than Task Manager. Which tool fits best?", options:["Resource Monitor","Disk Management","Registry Editor","Task Scheduler"], answer:0, explain:"<strong>Resource Monitor</strong> is correct because resmon shows detailed per-process CPU, disk, network, and memory activity in real time.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disk Management</b>: manages volumes.</span><span class='qd'><b>Registry Editor</b>: edits registry keys.</span><span class='qd'><b>Task Scheduler</b>: schedules tasks.</span>" },
{ id:"D1-042", domain:1, obj:"1.3", diff:"easy", q:"Which command opens the graphical Task Manager directly?", options:["taskmgr","tasklist","taskkill","taskschd.msc"], answer:0, explain:"<strong>taskmgr</strong> is correct because taskmgr launches Task Manager.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>tasklist</b>: is a command-line process list.</span><span class='qd'><b>taskkill</b>: ends processes from the command line.</span><span class='qd'><b>taskschd.msc</b>: opens Task Scheduler, not Task Manager.</span>" },
{ id:"D1-043", domain:1, obj:"1.3", diff:"hard", q:"A user reports a service repeatedly fails on startup. The technician wants to set the service to attempt a restart automatically after a failure. Where is this recovery option configured?", options:["In the service's Properties Recovery tab within services.msc","In Task Manager's Startup tab","In Device Manager's driver tab","In Disk Management volume properties"], answer:0, explain:"<strong>In the service's Properties Recovery tab within services.msc</strong> is correct because the Services snap-in lets you define first, second, and subsequent failure actions such as restart the service.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>In Task Manager's Startup tab</b>: this controls startup apps, not service recovery.</span><span class='qd'><b>In Device Manager's driver tab</b>: this manages drivers, not services.</span><span class='qd'><b>In Disk Management volume properties</b>: this manages disk volumes.</span>" },
{ id:"D1-044", domain:1, obj:"1.3", diff:"medium", q:"Which Task Manager tab allows a technician to enable or disable programs that automatically launch when Windows starts?", options:["Performance","Startup apps","Details","Users"], answer:1, explain:"<strong>Startup apps</strong> is correct because the Startup tab lists programs configured to run at login and shows their impact, allowing enable/disable.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Performance</b>: shows resource graphs.</span><span class='qd'><b>Details</b>: lists running processes with detailed columns.</span><span class='qd'><b>Users</b>: shows signed-in users and their resource use.</span>" },
{ id:"D1-045", domain:1, obj:"1.3", diff:"hard", q:"A technician needs to back up a registry key before editing it manually. Within Registry Editor, which action accomplishes this safely?", options:["Right-click the key and choose Export to save a .reg file","Delete the key and recreate it","Rename the key with a .bak suffix","Convert the key to a string value"], answer:0, explain:"<strong>Right-click the key and choose Export to save a .reg file</strong> is correct because exporting creates a restorable backup of the selected key before changes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Delete the key and recreate it</b>: deleting risks system damage and is not a backup.</span><span class='qd'><b>Rename the key with a .bak suffix</b>: registry keys are not backed up by renaming.</span><span class='qd'><b>Convert the key to a string value</b>: this is not a valid backup action.</span>" },
{ id:"D1-046", domain:1, obj:"1.4", diff:"easy", q:"Which Control Panel applet is used to uninstall a desktop application in Windows?", options:["Programs and Features","Device Manager","Internet Options","Sound"], answer:0, explain:"<strong>Programs and Features</strong> is correct because it lists installed desktop programs and provides the option to uninstall or change them.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Device Manager</b>: manages hardware, not installed apps.</span><span class='qd'><b>Internet Options</b>: configures browser and proxy settings.</span><span class='qd'><b>Sound</b>: configures audio devices.</span>" },
{ id:"D1-047", domain:1, obj:"1.4", diff:"medium", q:"A user needs to configure power and sleep behavior and choose a high performance plan. Which Control Panel applet provides power plans?", options:["Power Options","Ease of Access Center","Network and Sharing Center","Indexing Options"], answer:0, explain:"<strong>Power Options</strong> is correct because it manages power plans such as Balanced and High Performance and controls sleep behavior.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Ease of Access Center</b>: configures accessibility features.</span><span class='qd'><b>Network and Sharing Center</b>: manages network connections.</span><span class='qd'><b>Indexing Options</b>: manages search indexing.</span>" },
{ id:"D1-048", domain:1, obj:"1.4", diff:"medium", q:"A technician needs to adjust proxy server settings used by the system and legacy Internet Explorer. Which Control Panel applet contains these settings?", options:["Internet Options","Sound","Devices and Printers","File Explorer Options"], answer:0, explain:"<strong>Internet Options</strong> is correct because the Connections and LAN settings within Internet Options configure the system proxy.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Sound</b>: manages audio.</span><span class='qd'><b>Devices and Printers</b>: manages connected devices.</span><span class='qd'><b>File Explorer Options</b>: manages folder view settings.</span>" },
{ id:"D1-049", domain:1, obj:"1.4", diff:"easy", q:"Which Control Panel applet lets you show hidden files and display file extensions?", options:["File Explorer Options","Programs and Features","Region","Credential Manager"], answer:0, explain:"<strong>File Explorer Options</strong> is correct because its View tab includes options to show hidden files and unhide known file extensions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Programs and Features</b>: manages installed apps.</span><span class='qd'><b>Region</b>: sets locale and formats.</span><span class='qd'><b>Credential Manager</b>: stores saved credentials.</span>" },
{ id:"D1-050", domain:1, obj:"1.4", diff:"medium", q:"A user wants to change the date, time, and time zone. Which is the most appropriate location in the modern Windows Settings app?", options:["Time and Language","Accounts","Privacy","Gaming"], answer:0, explain:"<strong>Time and Language</strong> is correct because the Settings app groups date, time, time zone, and language under Time and Language.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Accounts</b>: manages sign-in and user accounts.</span><span class='qd'><b>Privacy</b>: controls app permissions.</span><span class='qd'><b>Gaming</b>: manages game-related features.</span>" },
{ id:"D1-051", domain:1, obj:"1.4", diff:"medium", q:"Where in the Windows Settings app would a technician go to check for and install operating system updates?", options:["Update and Security (Windows Update)","Personalization","Ease of Access","Apps"], answer:0, explain:"<strong>Update and Security (Windows Update)</strong> is correct because Windows Update under Update and Security handles checking for and installing OS updates.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Personalization</b>: changes themes and backgrounds.</span><span class='qd'><b>Ease of Access</b>: configures accessibility.</span><span class='qd'><b>Apps</b>: manages installed applications.</span>" },
{ id:"D1-052", domain:1, obj:"1.4", diff:"easy", q:"Which Control Panel applet manages saved usernames and passwords for websites and network resources?", options:["Credential Manager","User Accounts","Security and Maintenance","BitLocker"], answer:0, explain:"<strong>Credential Manager</strong> is correct because it stores and manages Windows and web credentials used for automatic sign-in.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>User Accounts</b>: manages local account types and settings.</span><span class='qd'><b>Security and Maintenance</b>: reports system health alerts.</span><span class='qd'><b>BitLocker</b>: manages drive encryption.</span>" },
{ id:"D1-053", domain:1, obj:"1.4", diff:"hard", q:"A technician needs to enable or disable optional Windows components such as the Telnet client or Hyper-V. Which Control Panel path provides this?", options:["Programs and Features then Turn Windows features on or off","Devices and Printers","Network and Sharing Center","Administrative Tools"], answer:0, explain:"<strong>Programs and Features then Turn Windows features on or off</strong> is correct because this dialog enables or disables optional OS features like the Telnet client and Hyper-V.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Devices and Printers</b>: manages hardware devices.</span><span class='qd'><b>Network and Sharing Center</b>: manages network connections.</span><span class='qd'><b>Administrative Tools</b>: contains management consoles but not the feature toggle.</span>" },
{ id:"D1-054", domain:1, obj:"1.4", diff:"medium", q:"A user wants to adjust the display resolution and arrange multiple monitors. In the modern Settings app, which category contains these options?", options:["System (Display)","Devices","Network and Internet","Accounts"], answer:0, explain:"<strong>System (Display)</strong> is correct because display resolution, scaling, and multi-monitor arrangement are under System then Display.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Devices</b>: manages peripherals like printers and Bluetooth.</span><span class='qd'><b>Network and Internet</b>: manages connectivity.</span><span class='qd'><b>Accounts</b>: manages sign-in options.</span>" },
{ id:"D1-055", domain:1, obj:"1.4", diff:"easy", q:"Which Control Panel applet allows a technician to configure mouse pointer speed and button behavior?", options:["Mouse","Keyboard","Region","Sound"], answer:0, explain:"<strong>Mouse</strong> is correct because the Mouse applet configures pointer speed, button assignments, and double-click speed.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Keyboard</b>: configures keyboard repeat and cursor blink rates.</span><span class='qd'><b>Region</b>: sets locale formats.</span><span class='qd'><b>Sound</b>: manages audio devices.</span>" },
{ id:"D1-056", domain:1, obj:"1.5", diff:"easy", q:"A user needs to access a folder shared from a server using the path \\\\FileSrv\\Accounting. What type of resource is this?", options:["A mapped registry hive","A network share","A local printer","A scheduled task"], answer:1, explain:"<strong>A network share</strong> is correct because a UNC path like \\\\FileSrv\\Accounting points to a shared folder over the network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A mapped registry hive</b>: registry hives are not accessed by UNC paths.</span><span class='qd'><b>A local printer</b>: this path references a folder share, not a printer queue.</span><span class='qd'><b>A scheduled task</b>: scheduled tasks are not UNC shares.</span>" },
{ id:"D1-057", domain:1, obj:"1.5", diff:"medium", q:"A technician must give a remote user encrypted access to the corporate network as if they were on-site. Which technology is the correct choice?", options:["Proxy server","VPN","Mapped drive","Windows Firewall"], answer:1, explain:"<strong>VPN</strong> is correct because a Virtual Private Network creates an encrypted tunnel allowing remote access to the internal network.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Proxy server</b>: forwards and filters traffic but does not create a secure tunnel to the LAN.</span><span class='qd'><b>Mapped drive</b>: assigns a drive letter to a share, not remote network access.</span><span class='qd'><b>Windows Firewall</b>: filters traffic, it does not provide remote access.</span>" },
{ id:"D1-058", domain:1, obj:"1.5", diff:"medium", q:"An administrator wants client web traffic to pass through a server that caches content and filters access to certain sites. Which feature is being described?", options:["VPN","Proxy server","Mapped drive","Network share"], answer:1, explain:"<strong>Proxy server</strong> is correct because a proxy intermediates client requests, can cache content, and filters access to sites.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>VPN</b>: provides an encrypted tunnel, not content filtering and caching.</span><span class='qd'><b>Mapped drive</b>: links a drive letter to a share.</span><span class='qd'><b>Network share</b>: is a shared folder, not a traffic intermediary.</span>" },
{ id:"D1-059", domain:1, obj:"1.5", diff:"medium", q:"A user can reach internal resources but cannot browse the internet, and the technician suspects a misconfigured firewall rule blocking outbound web traffic. Which Windows tool is most directly relevant?", options:["Windows Defender Firewall","Disk Management","Device Manager","Event Viewer"], answer:0, explain:"<strong>Windows Defender Firewall</strong> is correct because it controls inbound and outbound traffic rules and is where a blocked web port would be configured.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disk Management</b>: manages disks.</span><span class='qd'><b>Device Manager</b>: manages hardware.</span><span class='qd'><b>Event Viewer</b>: logs events but does not control firewall rules.</span>" },
{ id:"D1-060", domain:1, obj:"1.5", diff:"hard", q:"A technician needs every user on a workstation to automatically have drive S: connect to a share at logon. Which approach scales best in a domain?", options:["Manually run net use on each login","Use a Group Policy mapped drive or logon script","Copy the share contents to a local folder","Disable the firewall to allow the mapping"], answer:1, explain:"<strong>Use a Group Policy mapped drive or logon script</strong> is correct because Group Policy Preferences or a logon script can map drives automatically for users across the domain.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manually run net use on each login</b>: this does not scale and is error-prone.</span><span class='qd'><b>Copy the share contents to a local folder</b>: this breaks centralization and freshness.</span><span class='qd'><b>Disable the firewall to allow the mapping</b>: this is a security risk and unrelated to mapping.</span>" },
{ id:"D1-061", domain:1, obj:"1.5", diff:"medium", q:"When connecting to a corporate VPN, a user finds they can no longer reach local devices like a home printer. Which VPN setting most likely causes this?", options:["Split tunneling is disabled (full tunnel)","Proxy auto-detect is enabled","The firewall is turned off","The drive mapping expired"], answer:0, explain:"<strong>Split tunneling is disabled (full tunnel)</strong> is correct because in full tunnel mode all traffic routes through the VPN, cutting off direct local LAN access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Proxy auto-detect is enabled</b>: this affects web proxy discovery, not local device routing.</span><span class='qd'><b>The firewall is turned off</b>: disabling the firewall would not block local access.</span><span class='qd'><b>The drive mapping expired</b>: drive mappings are unrelated to printer reachability.</span>" },
{ id:"D1-062", domain:1, obj:"1.5", diff:"hard", q:"A technician wants to share a local folder so other users can read but not modify the contents, applying both share and NTFS permissions correctly. Which combination yields effective read-only access for network users?", options:["Share permission Read and NTFS Read combined","Share permission Full Control and NTFS Deny","Share permission Change and NTFS Modify","Share permission Read and NTFS Full Control"], answer:0, explain:"<strong>Share permission Read and NTFS Read combined</strong> is correct because the most restrictive of share and NTFS permissions applies over the network, so Read and Read yields effective read-only access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Share permission Full Control and NTFS Deny</b>: a Deny would block access entirely.</span><span class='qd'><b>Share permission Change and NTFS Modify</b>: this grants write access, not read-only.</span><span class='qd'><b>Share permission Read and NTFS Full Control</b>: the effective network permission is the more restrictive Read, but Full Control NTFS would grant write to local logons, which is not strictly read-only.</span>" },
{ id:"D1-063", domain:1, obj:"1.5", diff:"easy", q:"Which feature assigns a persistent drive letter on a workstation that points to a shared network folder?", options:["Mapped drive","Proxy","VPN","Firewall rule"], answer:0, explain:"<strong>Mapped drive</strong> is correct because mapping assigns a drive letter to a network share for convenient persistent access.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Proxy</b>: intermediates web traffic.</span><span class='qd'><b>VPN</b>: provides secure remote network access.</span><span class='qd'><b>Firewall rule</b>: controls traffic, not drive letters.</span>" },
{ id:"D1-064", domain:1, obj:"1.5", diff:"medium", q:"A technician wants to confirm whether a particular inbound port is allowed through Windows Defender Firewall. Where is the most precise place to check?", options:["Advanced Settings (Windows Defender Firewall with Advanced Security) Inbound Rules","Network and Sharing Center","Internet Options Security tab","Disk Management"], answer:0, explain:"<strong>Advanced Settings (Windows Defender Firewall with Advanced Security) Inbound Rules</strong> is correct because the advanced security console lists granular inbound rules including port allowances.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Network and Sharing Center</b>: shows network status, not firewall rules.</span><span class='qd'><b>Internet Options Security tab</b>: configures browser zones.</span><span class='qd'><b>Disk Management</b>: manages disks.</span>" },
{ id:"D1-065", domain:1, obj:"1.6", diff:"medium", q:"Before installing a large application, a technician must confirm the system meets requirements. Which factor is a typical system requirement to verify?", options:["The monitor refresh rate","Available free disk space and RAM","The keyboard layout","The default browser"], answer:1, explain:"<strong>Available free disk space and RAM</strong> is correct because applications specify minimum disk and memory requirements that must be met for proper installation and operation.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The monitor refresh rate</b>: rarely a hard install requirement.</span><span class='qd'><b>The keyboard layout</b>: does not affect installation.</span><span class='qd'><b>The default browser</b>: usually irrelevant to a desktop app's system requirements.</span>" },
{ id:"D1-066", domain:1, obj:"1.6", diff:"medium", q:"A technician must decide whether to deploy the 32-bit or 64-bit version of an application. Which consideration most directly determines compatibility?", options:["Whether the OS is 32-bit or 64-bit","The screen resolution","The mouse driver version","The default font size"], answer:0, explain:"<strong>Whether the OS is 32-bit or 64-bit</strong> is correct because a 64-bit application requires a 64-bit OS, while a 32-bit OS cannot run 64-bit software.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The screen resolution</b>: does not affect bitness compatibility.</span><span class='qd'><b>The mouse driver version</b>: is unrelated to application bitness.</span><span class='qd'><b>The default font size</b>: has no bearing on compatibility.</span>" },
{ id:"D1-067", domain:1, obj:"1.6", diff:"hard", q:"After installing a graphics-heavy CAD program, users report poor performance and crashes. The OS and disk meet requirements. Which additional requirement was most likely overlooked?", options:["A dedicated GPU meeting the application's video requirements","A larger monitor","A faster keyboard","A second network adapter"], answer:0, explain:"<strong>A dedicated GPU meeting the application's video requirements</strong> is correct because graphics-intensive applications require sufficient dedicated GPU resources, and an inadequate GPU causes poor performance and crashes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>A larger monitor</b>: display size does not affect rendering capability.</span><span class='qd'><b>A faster keyboard</b>: irrelevant to graphics performance.</span><span class='qd'><b>A second network adapter</b>: networking does not address local rendering needs.</span>" },
{ id:"D1-068", domain:1, obj:"1.6", diff:"medium", q:"A technician is deploying software to 200 workstations and wants a silent, scripted installation with no user prompts. Which installation method is most appropriate?", options:["Manually click through each installer","Use the installer's silent or unattended switches in a deployment script","Email the installer to each user","Burn the installer to individual DVDs"], answer:1, explain:"<strong>Use the installer's silent or unattended switches in a deployment script</strong> is correct because silent install switches allow automated, prompt-free deployment at scale.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Manually click through each installer</b>: does not scale to 200 machines.</span><span class='qd'><b>Email the installer to each user</b>: relies on users and is not automated.</span><span class='qd'><b>Burn the installer to individual DVDs</b>: is slow and impractical.</span>" },
{ id:"D1-069", domain:1, obj:"1.6", diff:"medium", q:"After installing a new line-of-business application, a technician should consider its impact on which of the following to ensure system stability?", options:["The desktop wallpaper","Device drivers, OS stability, and network resource usage","The mouse pointer scheme","The screen saver timeout"], answer:1, explain:"<strong>Device drivers, OS stability, and network resource usage</strong> is correct because new applications can affect drivers, overall OS stability, and consume network bandwidth, all of which must be considered.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The desktop wallpaper</b>: is cosmetic and not a stability concern.</span><span class='qd'><b>The mouse pointer scheme</b>: is cosmetic.</span><span class='qd'><b>The screen saver timeout</b>: does not affect application stability.</span>" },
{ id:"D1-070", domain:1, obj:"1.6", diff:"hard", q:"A technician must distribute an application from a network location and verify users have permission to read the installer and write to the install directory. Which two considerations are most relevant?", options:["Local user vs network permissions and impact on the network","Monitor calibration and font smoothing","Sound scheme and theme","Keyboard layout and date format"], answer:0, explain:"<strong>Local user vs network permissions and impact on the network</strong> is correct because installation from a network source requires appropriate permissions and the transfer impacts network resources.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Monitor calibration and font smoothing</b>: are cosmetic and irrelevant.</span><span class='qd'><b>Sound scheme and theme</b>: do not affect installation permissions.</span><span class='qd'><b>Keyboard layout and date format</b>: are unrelated to install rights.</span>" },
{ id:"D1-071", domain:1, obj:"1.7", diff:"easy", q:"Which file system is the default for modern Windows system drives and supports permissions, encryption, and large volumes?", options:["FAT32","NTFS","exFAT","ext4"], answer:1, explain:"<strong>NTFS</strong> is correct because NTFS is the default Windows file system supporting file permissions, EFS encryption, journaling, and large volumes.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FAT32</b>: lacks permissions and has a 4 GB file size limit.</span><span class='qd'><b>exFAT</b>: is designed for flash media without NTFS-style permissions.</span><span class='qd'><b>ext4</b>: is a Linux file system, not used on Windows.</span>" },
{ id:"D1-072", domain:1, obj:"1.7", diff:"medium", q:"A user needs to format a 128 GB USB flash drive to store single video files larger than 4 GB and use it across Windows and macOS. Which file system is the best choice?", options:["FAT32","exFAT","NTFS","ext4"], answer:1, explain:"<strong>exFAT</strong> is correct because exFAT supports files larger than 4 GB and is read/write compatible with both Windows and macOS.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FAT32</b>: has a 4 GB per-file limit, blocking large video files.</span><span class='qd'><b>NTFS</b>: is read-only by default on macOS without extra software.</span><span class='qd'><b>ext4</b>: is not natively supported by Windows or macOS.</span>" },
{ id:"D1-073", domain:1, obj:"1.7", diff:"easy", q:"Which file system is the modern default used by macOS, optimized for SSDs with snapshots and strong encryption?", options:["APFS","NTFS","ext4","FAT32"], answer:0, explain:"<strong>APFS</strong> is correct because Apple File System is the default for modern macOS, optimized for flash storage with snapshots and encryption.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>NTFS</b>: is the Windows file system.</span><span class='qd'><b>ext4</b>: is a Linux file system.</span><span class='qd'><b>FAT32</b>: is an old cross-platform file system, not the macOS default.</span>" },
{ id:"D1-074", domain:1, obj:"1.7", diff:"easy", q:"Which file system is most commonly used by Linux distributions for the root partition?", options:["NTFS","ext4","exFAT","APFS"], answer:1, explain:"<strong>ext4</strong> is correct because ext4 is the most common default journaling file system for Linux root partitions.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>NTFS</b>: is the Windows file system.</span><span class='qd'><b>exFAT</b>: is used for removable flash media.</span><span class='qd'><b>APFS</b>: is the macOS file system.</span>" },
{ id:"D1-075", domain:1, obj:"1.7", diff:"medium", q:"A small business needs an operating system to run on inexpensive laptops that boot quickly, rely on web apps, and are easy to manage through a cloud console. Which OS best fits?", options:["ChromeOS","Windows Server","iOS","macOS"], answer:0, explain:"<strong>ChromeOS</strong> is correct because ChromeOS is a lightweight, web-centric OS managed through a cloud console, ideal for inexpensive laptops.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Windows Server</b>: is a server OS, not for end-user laptops.</span><span class='qd'><b>iOS</b>: runs on Apple mobile devices, not laptops.</span><span class='qd'><b>macOS</b>: runs only on Apple computers and is not low-cost.</span>" },
{ id:"D1-076", domain:1, obj:"1.7", diff:"medium", q:"Which mobile operating system is open source and used by a wide range of hardware manufacturers?", options:["iOS","Android","macOS","ChromeOS"], answer:1, explain:"<strong>Android</strong> is correct because Android is open source and licensed to many hardware manufacturers across diverse devices.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>iOS</b>: is closed source and exclusive to Apple devices.</span><span class='qd'><b>macOS</b>: is a desktop OS for Apple computers.</span><span class='qd'><b>ChromeOS</b>: is a laptop/desktop web-centric OS, not a phone OS.</span>" },
{ id:"D1-077", domain:1, obj:"1.7", diff:"medium", q:"What is the primary distinction between a workstation operating system and a server operating system?", options:["Servers cannot run any applications","A server OS is optimized to provide shared services and concurrent connections to many clients","A workstation OS cannot connect to a network","Server operating systems lack a file system"], answer:1, explain:"<strong>A server OS is optimized to provide shared services and concurrent connections to many clients</strong> is correct because server operating systems are tuned for roles like file, web, and directory services handling many simultaneous clients.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Servers cannot run any applications</b>: servers do run server applications.</span><span class='qd'><b>A workstation OS cannot connect to a network</b>: workstations are network capable.</span><span class='qd'><b>Server operating systems lack a file system</b>: all general OSes use file systems.</span>" },
{ id:"D1-078", domain:1, obj:"1.7", diff:"hard", q:"A technician needs an OS for a developer who wants a free, highly customizable environment with a powerful shell, package managers, and the ability to run on varied hardware. Which OS is the best match?", options:["iOS","Linux","ChromeOS","Windows Home"], answer:1, explain:"<strong>Linux</strong> is correct because Linux is free, open source, highly customizable, includes powerful shells and package managers like apt and yum, and runs on diverse hardware.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>iOS</b>: is a closed mobile OS with limited customization.</span><span class='qd'><b>ChromeOS</b>: is web-centric with limited native development flexibility.</span><span class='qd'><b>Windows Home</b>: is not free and is less customizable at the shell level.</span>" },
{ id:"D1-079", domain:1, obj:"1.7", diff:"easy", q:"Which operating system runs exclusively on Apple desktop and laptop computers?", options:["Android","macOS","Linux","ChromeOS"], answer:1, explain:"<strong>macOS</strong> is correct because macOS is Apple's desktop and laptop operating system, running only on Apple hardware.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Android</b>: is a mobile OS used on many vendors' devices.</span><span class='qd'><b>Linux</b>: runs on a broad range of hardware, not Apple-exclusive.</span><span class='qd'><b>ChromeOS</b>: runs on Chromebooks, not Apple computers.</span>" },
{ id:"D1-080", domain:1, obj:"1.7", diff:"hard", q:"A user wants to encrypt files on a USB drive with built-in Windows file-level encryption (EFS). Which file system must the drive use?", options:["FAT32","exFAT","NTFS","ext4"], answer:2, explain:"<strong>NTFS</strong> is correct because the Encrypting File System (EFS) is an NTFS feature and is not available on FAT32 or exFAT.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>FAT32</b>: does not support EFS or file permissions.</span><span class='qd'><b>exFAT</b>: lacks EFS support.</span><span class='qd'><b>ext4</b>: is a Linux file system and not used for Windows EFS.</span>" },
{ id:"D1-081", domain:1, obj:"1.8", diff:"medium", q:"A technician is partitioning a 4 TB drive and needs support for more than four primary partitions and volumes larger than 2 TB. Which partition style is required?", options:["MBR","GPT","FAT","exFAT"], answer:1, explain:"<strong>GPT</strong> is correct because GUID Partition Table supports volumes larger than 2 TB and many more partitions than MBR.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>MBR</b>: is limited to 2 TB and four primary partitions.</span><span class='qd'><b>FAT</b>: is a file system, not a partition style.</span><span class='qd'><b>exFAT</b>: is a file system, not a partition style.</span>" },
{ id:"D1-082", domain:1, obj:"1.8", diff:"hard", q:"A technician wants to upgrade Windows 10 to Windows 11 while keeping all user files, settings, and installed applications. Which installation method should be used?", options:["Clean install","In-place upgrade","Bare-metal reimage","Recovery partition wipe"], answer:1, explain:"<strong>In-place upgrade</strong> is correct because an in-place upgrade installs the new OS while preserving user files, settings, and applications.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Clean install</b>: erases the drive and removes apps and settings.</span><span class='qd'><b>Bare-metal reimage</b>: deploys a fresh image, losing existing data.</span><span class='qd'><b>Recovery partition wipe</b>: resets the system, not an upgrade that preserves apps.</span>" },
{ id:"D1-083", domain:1, obj:"1.8", diff:"medium", q:"A technician wants to install Windows on multiple machines by booting them from a network server image. Which boot/install method is being used?", options:["Optical media install","PXE (network) boot installation","USB recovery install","Cloud reset"], answer:1, explain:"<strong>PXE (network) boot installation</strong> is correct because PXE allows a client to boot and load an installation image from a network server.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Optical media install</b>: uses a local DVD, not the network.</span><span class='qd'><b>USB recovery install</b>: boots from local USB media.</span><span class='qd'><b>Cloud reset</b>: reinstalls from cloud download on an existing machine, not a network boot deployment.</span>" },
{ id:"D1-084", domain:1, obj:"1.8", diff:"medium", q:"A technician needs to perform a fresh installation that erases the existing OS and all data on the system drive. Which installation type is this?", options:["In-place upgrade","Clean install","Repair install","Feature update"], answer:1, explain:"<strong>Clean install</strong> is correct because a clean install wipes the target volume and installs the OS fresh with no carried-over data.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>In-place upgrade</b>: preserves files and apps.</span><span class='qd'><b>Repair install</b>: reinstalls system files while keeping data.</span><span class='qd'><b>Feature update</b>: updates an existing OS version without wiping data.</span>" },
{ id:"D1-085", domain:1, obj:"1.8", diff:"hard", q:"A technician must install a 64-bit OS that boots in UEFI mode with Secure Boot. Which partition style is required for the boot disk?", options:["MBR","GPT","Dynamic disk","Logical-only"], answer:1, explain:"<strong>GPT</strong> is correct because UEFI with Secure Boot requires a GPT-partitioned boot disk.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>MBR</b>: is used with legacy BIOS booting, not UEFI Secure Boot.</span><span class='qd'><b>Dynamic disk</b>: is a Windows volume management mode, not a boot partition style for UEFI.</span><span class='qd'><b>Logical-only</b>: is not a valid partition style.</span>" },
{ id:"D1-086", domain:1, obj:"1.8", diff:"medium", q:"Before upgrading the OS, what is the most important step a technician should take to protect user data?", options:["Defragment the registry","Back up user data","Increase the screen resolution","Disable the antivirus permanently"], answer:1, explain:"<strong>Back up user data</strong> is correct because backing up protects against data loss if the upgrade fails or behaves unexpectedly.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Defragment the registry</b>: is not a standard pre-upgrade safeguard.</span><span class='qd'><b>Increase the screen resolution</b>: does not protect data.</span><span class='qd'><b>Disable the antivirus permanently</b>: leaves the system unprotected and is unnecessary.</span>" },
{ id:"D1-087", domain:1, obj:"1.8", diff:"hard", q:"A technician images 50 identical PCs from a master image and must ensure each machine has a unique security identifier and computer name. Which tool prepares the master image for cloning?", options:["sysprep","diskpart","robocopy","gpupdate"], answer:0, explain:"<strong>sysprep</strong> is correct because the System Preparation tool generalizes an image, removing machine-specific data like the SID so clones receive unique identifiers.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>diskpart</b>: manages partitions, it does not generalize images.</span><span class='qd'><b>robocopy</b>: copies files.</span><span class='qd'><b>gpupdate</b>: refreshes Group Policy.</span>" },
{ id:"D1-088", domain:1, obj:"1.8", diff:"easy", q:"Which legacy partition style is limited to a maximum of four primary partitions and a 2 TB disk size?", options:["GPT","MBR","NTFS","APFS"], answer:1, explain:"<strong>MBR</strong> is correct because the Master Boot Record style supports up to four primary partitions and disks up to 2 TB.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>GPT</b>: supports far more partitions and larger disks.</span><span class='qd'><b>NTFS</b>: is a file system, not a partition style.</span><span class='qd'><b>APFS</b>: is a macOS file system, not a partition style.</span>" },
{ id:"D1-089", domain:1, obj:"1.9", diff:"easy", q:"Which macOS feature provides automated, scheduled backups to an external or networked drive and lets users restore previous versions of files?", options:["Disk Utility","Time Machine","Spotlight","Mission Control"], answer:1, explain:"<strong>Time Machine</strong> is correct because Time Machine performs automatic incremental backups and allows restoring earlier versions of files.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Disk Utility</b>: manages disks and volumes.</span><span class='qd'><b>Spotlight</b>: is the system search feature.</span><span class='qd'><b>Mission Control</b>: manages open windows and desktops.</span>" },
{ id:"D1-090", domain:1, obj:"1.9", diff:"medium", q:"On macOS, a technician needs to repair a disk, erase a volume, or create a disk image. Which built-in utility provides these functions?", options:["Time Machine","Disk Utility","Terminal","Keychain Access"], answer:1, explain:"<strong>Disk Utility</strong> is correct because Disk Utility manages volumes, runs First Aid repairs, erases drives, and creates disk images.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Time Machine</b>: handles backups, not disk repair.</span><span class='qd'><b>Terminal</b>: is the command-line shell, not a dedicated disk GUI.</span><span class='qd'><b>Keychain Access</b>: manages stored credentials.</span>" },
{ id:"D1-091", domain:1, obj:"1.9", diff:"easy", q:"Which Linux command lists the files and directories in the current directory?", options:["ls","dir","cat","pwd"], answer:0, explain:"<strong>ls</strong> is correct because ls lists directory contents on Linux and macOS.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>dir</b>: is the Windows listing command.</span><span class='qd'><b>cat</b>: displays file contents.</span><span class='qd'><b>pwd</b>: prints the current directory path.</span>" },
{ id:"D1-092", domain:1, obj:"1.9", diff:"medium", q:"A Linux administrator needs to search a log file for lines containing the word error. Which command is most appropriate?", options:["grep error logfile","chmod error logfile","ps error logfile","apt error logfile"], answer:0, explain:"<strong>grep error logfile</strong> is correct because grep searches text for matching patterns and prints the matching lines.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chmod error logfile</b>: chmod changes file permissions.</span><span class='qd'><b>ps error logfile</b>: ps lists processes.</span><span class='qd'><b>apt error logfile</b>: apt manages packages.</span>" },
{ id:"D1-093", domain:1, obj:"1.9", diff:"medium", q:"A Linux user wants to change a script's permissions to make it executable by the owner. Which command does this?", options:["chmod","chown","grep","ps"], answer:0, explain:"<strong>chmod</strong> is correct because chmod modifies file permission bits, such as adding execute permission.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chown</b>: changes file ownership, not permissions.</span><span class='qd'><b>grep</b>: searches text.</span><span class='qd'><b>ps</b>: lists processes.</span>" },
{ id:"D1-094", domain:1, obj:"1.9", diff:"medium", q:"A standard Linux user must run a single command with administrative privileges. Which command should prefix the command?", options:["sudo","ls","ps","grep"], answer:0, explain:"<strong>sudo</strong> is correct because sudo executes a command with elevated (superuser) privileges for authorized users.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ls</b>: lists directory contents.</span><span class='qd'><b>ps</b>: lists processes.</span><span class='qd'><b>grep</b>: searches text.</span>" },
{ id:"D1-095", domain:1, obj:"1.9", diff:"medium", q:"On a Debian or Ubuntu system, which command installs a software package from the configured repositories?", options:["yum install","apt install","dd install","ps install"], answer:1, explain:"<strong>apt install</strong> is correct because apt is the package manager for Debian and Ubuntu used to install software.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>yum install</b>: yum is used on Red Hat-based systems, not Debian/Ubuntu.</span><span class='qd'><b>dd install</b>: dd copies and converts data, it does not install packages.</span><span class='qd'><b>ps install</b>: ps lists processes.</span>" },
{ id:"D1-096", domain:1, obj:"1.9", diff:"medium", q:"On a Red Hat-based Linux system, which command is traditionally used to install packages?", options:["apt","yum","grep","chmod"], answer:1, explain:"<strong>yum</strong> is correct because yum (and its successor dnf) is the package manager for Red Hat-based distributions like CentOS and Fedora.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>apt</b>: is used on Debian-based systems.</span><span class='qd'><b>grep</b>: searches text.</span><span class='qd'><b>chmod</b>: changes permissions.</span>" },
{ id:"D1-097", domain:1, obj:"1.9", diff:"hard", q:"A technician needs to create a bit-for-bit copy of a disk or write an ISO image to a USB drive on Linux. Which command performs low-level block copying?", options:["dd","ls","grep","chown"], answer:0, explain:"<strong>dd</strong> is correct because dd copies and converts data at the block level, used for disk imaging and writing ISOs to drives.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ls</b>: lists files.</span><span class='qd'><b>grep</b>: searches text.</span><span class='qd'><b>chown</b>: changes ownership.</span>" },
{ id:"D1-098", domain:1, obj:"1.9", diff:"medium", q:"A Linux administrator wants to view currently running processes including their PIDs. Which command is most appropriate?", options:["ps","cd","dd","apt"], answer:0, explain:"<strong>ps</strong> is correct because ps reports a snapshot of current processes with details like PID and command.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>cd</b>: changes the working directory.</span><span class='qd'><b>dd</b>: copies data blocks.</span><span class='qd'><b>apt</b>: manages packages.</span>" },
{ id:"D1-099", domain:1, obj:"1.9", diff:"easy", q:"On macOS or Linux, which command opens a command-line shell environment for typing commands?", options:["Terminal","Finder","Spotlight","Dock"], answer:0, explain:"<strong>Terminal</strong> is correct because Terminal provides a command-line shell on macOS and Linux for running commands.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Finder</b>: is the macOS graphical file manager.</span><span class='qd'><b>Spotlight</b>: is the macOS search feature.</span><span class='qd'><b>Dock</b>: is the macOS application launcher bar.</span>" },
{ id:"D1-100", domain:1, obj:"1.9", diff:"hard", q:"A Linux administrator must change the owner of a file to the user named webadmin. Which command accomplishes this?", options:["chmod webadmin file","chown webadmin file","grep webadmin file","sudo webadmin file"], answer:1, explain:"<strong>chown webadmin file</strong> is correct because chown changes the ownership of a file or directory to the specified user.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>chmod webadmin file</b>: chmod changes permission bits, not ownership.</span><span class='qd'><b>grep webadmin file</b>: grep searches text within files.</span><span class='qd'><b>sudo webadmin file</b>: sudo elevates a command but webadmin is not a command.</span>" },
{ id:"D1-101", domain:1, obj:"1.1", diff:"easy", q:"Which Windows edition is designed for home users and lacks domain join and BitLocker by default?", options:["Windows Pro","Windows Home","Windows Enterprise","Windows Pro for Workstations"], answer:1, explain:"<strong>Windows Home</strong> is correct because the Home edition targets consumers and omits business features like domain join and BitLocker.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Windows Pro</b>: includes domain join and BitLocker.</span><span class='qd'><b>Windows Enterprise</b>: adds advanced management for large organizations.</span><span class='qd'><b>Windows Pro for Workstations</b>: targets high-end hardware with extra features.</span>" },
{ id:"D1-102", domain:1, obj:"1.1", diff:"medium", q:"A small business wants to join its workstations to an Active Directory domain. Which is the minimum Windows edition that supports domain join?", options:["Windows Home","Windows Pro","Windows S mode only","Windows IoT Core"], answer:1, explain:"<strong>Windows Pro</strong> is correct because domain join is available starting with the Pro edition, while Home does not support it.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Windows Home</b>: cannot join a domain.</span><span class='qd'><b>Windows S mode only</b>: S mode restricts apps and is not an edition that adds domain join.</span><span class='qd'><b>Windows IoT Core</b>: targets embedded devices, not general workstations.</span>" },
{ id:"D1-103", domain:1, obj:"1.1", diff:"medium", q:"Which Windows edition is licensed primarily through volume agreements and includes features like AppLocker and advanced security management for large organizations?", options:["Windows Home","Windows Pro","Windows Enterprise","Windows Education Basic"], answer:2, explain:"<strong>Windows Enterprise</strong> is correct because Enterprise is offered via volume licensing and adds advanced features such as AppLocker for large organizations.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Windows Home</b>: lacks enterprise management features.</span><span class='qd'><b>Windows Pro</b>: includes business features but not the full Enterprise feature set.</span><span class='qd'><b>Windows Education Basic</b>: is not a standard edition name.</span>" },
{ id:"D1-104", domain:1, obj:"1.1", diff:"hard", q:"A technician needs to know the maximum amount of RAM an installed Windows edition supports before adding 256 GB of memory. Which factor most directly governs this limit?", options:["The desktop theme","The Windows edition and whether it is 64-bit","The default browser","The screen resolution"], answer:1, explain:"<strong>The Windows edition and whether it is 64-bit</strong> is correct because RAM limits differ by edition (Home vs Pro vs Enterprise) and 32-bit Windows caps at about 4 GB regardless of edition.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>The desktop theme</b>: is cosmetic and does not affect RAM limits.</span><span class='qd'><b>The default browser</b>: is unrelated to memory support.</span><span class='qd'><b>The screen resolution</b>: does not determine RAM capacity.</span>" },
{ id:"D1-105", domain:1, obj:"1.1", diff:"medium", q:"Which feature, available in Windows Pro but not Home, encrypts an entire drive to protect data if the device is lost or stolen?", options:["BitLocker","Defender Firewall","Storage Spaces","Disk Cleanup"], answer:0, explain:"<strong>BitLocker</strong> is correct because BitLocker full-disk encryption is included in Pro and Enterprise but not Home.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Defender Firewall</b>: is available in all editions and does not encrypt drives.</span><span class='qd'><b>Storage Spaces</b>: pools storage and is available across editions.</span><span class='qd'><b>Disk Cleanup</b>: removes temporary files, it does not encrypt.</span>" },
{ id:"D1-106", domain:1, obj:"1.1", diff:"hard", q:"An organization wants centralized control over which group policies apply and the ability to use Remote Desktop hosting incoming connections. Which is the minimum edition that supports being a Remote Desktop host?", options:["Windows Home","Windows Pro","Windows S mode","Windows IoT"], answer:1, explain:"<strong>Windows Pro</strong> is correct because hosting incoming Remote Desktop connections and full Group Policy support begin with the Pro edition; Home can only act as an RDP client.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Windows Home</b>: can connect out via RDP but cannot host incoming sessions or use the Group Policy Editor.</span><span class='qd'><b>Windows S mode</b>: is a locked-down configuration, not the edition that enables RDP hosting.</span><span class='qd'><b>Windows IoT</b>: targets embedded scenarios.</span>" },
{ id:"D1-107", domain:1, obj:"1.3", diff:"medium", q:"A technician opens Computer Management and wants to use the snap-in for viewing logs, managing local users and groups, and disk volumes in one place. Which command launches Computer Management?", options:["compmgmt.msc","diskmgmt.msc","services.msc","eventvwr"], answer:0, explain:"<strong>compmgmt.msc</strong> is correct because compmgmt.msc opens Computer Management, which combines Event Viewer, Local Users and Groups, Disk Management, and more.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>diskmgmt.msc</b>: opens only Disk Management.</span><span class='qd'><b>services.msc</b>: opens only the Services snap-in.</span><span class='qd'><b>eventvwr</b>: opens only Event Viewer.</span>" },
{ id:"D1-108", domain:1, obj:"1.2", diff:"hard", q:"A technician needs a continuous ping to a gateway to watch for intermittent drops over several minutes. Which command achieves a continuous ping on Windows?", options:["ping -n 4 gateway","ping -t gateway","ping -a gateway","ping -l gateway"], answer:1, explain:"<strong>ping -t gateway</strong> is correct because -t pings continuously until manually stopped, ideal for observing intermittent loss.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>ping -n 4 gateway</b>: sends a fixed count of four echoes.</span><span class='qd'><b>ping -a gateway</b>: resolves the address to a hostname.</span><span class='qd'><b>ping -l gateway</b>: sets the packet size and requires a value.</span>" },
{ id:"D1-109", domain:1, obj:"1.4", diff:"hard", q:"A technician notices that on a modern Windows system some configuration tasks exist only in the Settings app while others remain in Control Panel. Which statement best describes the current relationship?", options:["Control Panel has been fully removed","Microsoft is gradually migrating settings to the Settings app while some legacy applets still reside in Control Panel","The Settings app only works offline","Control Panel and Settings cannot both be open"], answer:1, explain:"<strong>Microsoft is gradually migrating settings to the Settings app while some legacy applets still reside in Control Panel</strong> is correct because Windows is transitioning configuration to the Settings app, though several legacy applets remain in Control Panel.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Control Panel has been fully removed</b>: it still exists in current Windows.</span><span class='qd'><b>The Settings app only works offline</b>: it works online and offline.</span><span class='qd'><b>Control Panel and Settings cannot both be open</b>: both can run simultaneously.</span>" },
{ id:"D1-110", domain:1, obj:"1.9", diff:"hard", q:"A macOS user needs to install command-line developer software but is unsure how packages are typically managed outside the App Store. Which approach is most commonly used for open-source command-line tools on macOS?", options:["Use yum, the native macOS package manager","Use a third-party package manager such as Homebrew from Terminal","Use Time Machine to download apps","Use Disk Utility to fetch software"], answer:1, explain:"<strong>Use a third-party package manager such as Homebrew from Terminal</strong> is correct because macOS does not ship a built-in CLI package manager, so tools like Homebrew are commonly used to install open-source command-line software.<br><span class='qwhy'>Why the other options are wrong:</span><span class='qd'><b>Use yum, the native macOS package manager</b>: yum is a Linux tool and is not native to macOS.</span><span class='qd'><b>Use Time Machine to download apps</b>: Time Machine performs backups, not installs.</span><span class='qd'><b>Use Disk Utility to fetch software</b>: Disk Utility manages disks, not software installation.</span>" }
);
